('ACT_WBPR690', 'Web Programming', 'USR_JNPR65e', 378000, 'https://icety-data.is3.cloudhost.id/IMAGE_ACTIVITY/Image-Activity-1755761028-1755761028.jpg', 1, NULL, 'https://icety-data.is3.cloudhost.id/SERTIF_IMAGE/Sertificate-Template-1759653349-1759653349.jpg', '2025-08-19 14:19:00', '2027-08-21 23:59:00', 1, 1, '2025-10-27 08:36:51', '<p><span style=\"color: rgb(83, 83, 95);\">Sertifikat ini membuktikan bahwa Anda telah menguasai keterampilan dasar dalam bidang </span><span data-start=\"86\" data-end=\"105\" style=\"color: rgb(83, 83, 95);\">Web Programming.</span></p>', '<p>6,</p><p>Basic HTML &amp; CSS</p><p>CSS Layouting</p><p>Basic JavaScript</p><p>DOM Manipulation &amp; Event Handling</p><p>CSS Animation &amp; Transition</p><p>Website Deployment</p>', NULL, 'Web Programming', NULL, NULL, 'joinprogram', '<p style=\"margin-bottom: 1rem; color: rgb(119, 131, 143); line-height: 30px; font-family: Jost, sans-serif; font-size: 16px;\">Ada 2 Instruktur pada Web Programming Course yaitu;</p><p style=\"margin-bottom: 1rem; color: rgb(119, 131, 143); line-height: 30px; font-family: Jost, sans-serif; font-size: 16px;\">Kak Teguh dan Kak Alan</p>', NULL);
INSERT INTO `blog` (`ID_BLOG`, `TITLE_BLOG`, `CATEGORY_BLOG`, `IMAGE_BLOG`, `TEXT_BLOG`, `DATE_UPLOAD`) VALUES
(3, 'Mengapa Kebersihan Dapur adalah Kunci dalam Industri Makanan', 'Kebersihan dan Sanitasi di Industri Makanan', 'https://expo-dev.is3.cloudhost.id/IMAGE_BLOG/Image-Blog-1736839899-1736839899.png', 'Dapur yang bersih dan terorganisir sangat penting, terutama di lingkungan yang melibatkan penyediaan makanan seperti restoran, hotel, dan kantin kampus. Kebersihan dapur tidak hanya memastikan kualitas makanan tetap terjaga, tetapi juga mencegah penyebaran penyakit bawaan makanan. Di artikel ini, kami akan menjelaskan alasan utama mengapa kebersihan dapur adalah prioritas yang tidak bisa diabaikan dan bagaimana Anda dapat meningkatkan standar kebersihan di dapur Anda.\r\n\r\nKebersihan dapur sangat penting untuk mengurangi risiko penyakit bawaan makanan yang disebabkan oleh bakteri seperti salmonella dan E. coli, yang dapat menyebar dengan cepat melalui permukaan yang terkontaminasi. Prosedur sanitasi yang ketat membantu memastikan bahwa semua permukaan dapur, peralatan, dan tangan staf dapur tetap bersih. Selain itu, kebersihan juga berperan dalam menjaga kualitas dan rasa makanan, karena bahan makanan yang disimpan dengan benar dapat mempertahankan kesegarannya, mencegah kontaminasi, dan memberikan pengalaman terbaik kepada pelanggan. Mematuhi regulasi kesehatan dan keamanan sangatlah penting untuk menghindari denda dan menjaga keberlangsungan bisnis. Dapur yang bersih dan terorganisir juga meningkatkan efisiensi operasional, memungkinkan staf bekerja lebih efektif tanpa hambatan dari sampah atau benda yang berantakan. Hal ini tidak hanya mempermudah pekerjaan mereka tetapi juga mengurangi risiko kecelakaan kerja. Selain itu, dapur yang bersih meningkatkan kepuasan pelanggan dan reputasi bisnis, terutama di restoran dengan dapur terbuka, di mana pelanggan bisa melihat langsung bagaimana makanan disiapkan. Menjaga kebersihan dapur secara konsisten memperlihatkan profesionalisme dan komitmen Anda terhadap kesehatan dan keselamatan.\r\n\r\nKebersihan dapur bukanlah hal yang bisa ditawar-tawar. Dengan memastikan dapur Anda tetap bersih dan terjaga, Anda melindungi pelanggan, mematuhi regulasi, dan mempertahankan reputasi bisnis. Pelajari lebih lanjut tentang praktik terbaik kebersihan dapur dengan mengikuti kursus kami di ICETy.org, atau unduh ebook kami untuk panduan komprehensif.', '2025-01-14'),
(4, 'Mengapa Kebersihan Toilet Harus Jadi Prioritas di Tempat Umum', 'Kebersihan dan Sanitasi Umum', 'https://expo-dev.is3.cloudhost.id/IMAGE_BLOG/Image-Blog-1736839960-1736839960.png', 'Toilet umum yang bersih adalah salah satu fasilitas penting yang mendukung kesehatan masyarakat. Sayangnya, kebersihan toilet sering kali terabaikan, padahal area ini dapat menjadi sarang kuman dan bakteri jika tidak dijaga dengan baik. Di artikel ini, kami akan menjelaskan alasan mengapa menjaga kebersihan toilet adalah prioritas utama, terutama di lingkungan seperti kantor, restoran, kampus, rumah sakit, dan hotel.\r\n\r\nToilet yang bersih memiliki dampak langsung terhadap kesehatan dan kenyamanan pengguna. Area toilet yang tidak terawat bisa menjadi tempat berkembang biak bagi patogen berbahaya seperti E. coli, staphylococcus, dan virus gastrointestinal, yang dapat menyebabkan penyebaran penyakit dengan cepat. Dengan memastikan toilet tetap higienis, kita mengurangi risiko infeksi dan melindungi kesehatan orang-orang yang menggunakan fasilitas tersebut, termasuk karyawan dan pengunjung. Tidak hanya itu, toilet yang bersih menciptakan kesan positif dan menunjukkan profesionalisme suatu tempat, yang sangat penting bagi bisnis seperti restoran, hotel, dan perkantoran. Kebersihan toilet juga memengaruhi tingkat kepuasan dan kenyamanan pengunjung. Bayangkan sebuah restoran yang memiliki makanan enak tetapi toiletnya kotor; hal ini dapat membuat pengunjung enggan kembali. Implementasi pembersihan rutin, penggunaan produk desinfektan yang tepat, dan memastikan adanya persediaan seperti sabun tangan dan tisu toilet adalah langkah-langkah yang sangat penting. Pelatihan staf kebersihan tentang cara membersihkan toilet secara efisien, termasuk prosedur sanitasi lantai, pegangan pintu, wastafel, dan mangkuk toilet, juga menjadi bagian krusial dari program sanitasi. Lingkungan seperti rumah sakit dan sekolah memiliki kebutuhan kebersihan yang lebih tinggi karena banyaknya orang yang menggunakan fasilitas tersebut, sehingga perlu perhatian khusus untuk menjaga area toilet tetap bebas kuman. Solusi inovatif, seperti sensor keran otomatis dan dispenser tanpa sentuhan, bisa membantu mengurangi risiko penularan penyakit. Selain itu, inspeksi kebersihan secara berkala dapat memastikan bahwa standar sanitasi selalu terpenuhi.\r\n\r\nKebersihan toilet adalah aspek penting yang tidak boleh diabaikan, baik di tempat umum maupun tempat kerja. Dengan menjaga standar kebersihan yang tinggi, Anda melindungi kesehatan pengguna, menciptakan kesan positif, dan meningkatkan kenyamanan secara keseluruhan. Untuk tips lebih lanjut tentang menjaga kebersihan toilet dan area lainnya, kunjungi ICETy.org, tempat Anda dapat menemukan kursus dan ebook yang berguna.', '2025-01-14');
