INSERT INTO `course` (`ID_COURSE`, `ID_ACTIVITY`, `REQUIREMENT`, `PENGUMUMAN`, `DESKRIPSI_COURSE`, `DESKRIPSI_COURSE_ITEM`, `KATEGORI`, `SUMMARY`, `STATUS`, `FINAL_EXAM`, `ALIAS`, `DURATION`, `HOURS`, `IS_SERTIF_PAID`, `PRICE_SERTIF`, `FINAL_JMKP`, `PRICE_JMKP`) VALUES
('ACT_PBSR412', 'ACT_MDLGad7', NULL, '<p><b>Sertifikat – Teaching with Gamification (32 JP).</b></p><div><div><font color=\"#72849a\">Sertifikat ini diberikan sebagai bukti bahwa peserta telah mengikuti dan menyelesaikan pelatihan Gamification in Deep Learning selama 32 Jam Pelajaran (JP), dengan ketentuan:</font></div><div><font color=\"#72849a\">a. Harus diselesaikan oleh peserta dalam durasi belajar yang telah ditentukan.</font></div><div><font color=\"#72849a\">b. Diberikan kepada peserta yang telah menyelesaikan seluruh chapter dan lulus Evaluasi dengan minimal skor 80%.</font></div><div><font color=\"#72849a\">c. Sertifikat ini menandakan bahwa peserta telah mengikuti dan menyelesaikan pelatihan secara lengkap.</font></div><div><br></div></div><div><font color=\"#72849a\"><b>Sertifikat Kompetensi – Teaching with Gamification</b></font></div><div><span style=\"color: rgb(114, 132, 154);\"><br></span></div><div><span style=\"color: rgb(114, 132, 154);\">Sertifikat ini bersifat opsional dan diberikan kepada peserta yang ingin mengukur penguasaan kompetensinya secara lebih mendalam melalui Uji Kompetensi Akhir, dengan ketentuan:</span></div><div><font color=\"#72849a\">a. Sertifikat ini bukan bagian dari pelatihan 32 JP, dan bersifat tambahan</font></div><div><font color=\"#72849a\">b. Dikeluarkan oleh Pelangi Edukasi dan Yayasan TAGAME.</font></div><div><font color=\"#72849a\">c. Peserta dapat mengikuti ujian tambahan (Final Exam) dengan biaya terpisah, setelah lulus dengan minimal skor 80%.</font></div><div><font color=\"#72849a\">d. Ujian Sertifikat Achievement harus diselesaikan dalam waktu maksimal 1 minggu setelah akun Uji Kompetensi ini diaktifkan.</font></div><div><font color=\"#72849a\">e. Sertifikat diterbitkan jika peserta lulus dengan passing grade minimal 80% pada Uji Kompetensi ini</font></div>', '<p class=\"MsoNormal\" style=\"text-align:justify\"><b><span lang=\"EN-ID\" style=\"font-size:16.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri\">“Teaching with Gamification: Jadikan\r\nPembelajaran Lebih Menyenangkan dan Memotivasi!”<o:p></o:p></span></b></p>\r\n\r\n<p class=\"MsoNormal\" style=\"text-align:justify\"><span style=\"font-size:12.0pt;\r\nline-height:107%;font-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:Calibri;\r\nmso-ansi-language:EN-US\">Kursus ini dirancang untuk guru dan pendidik yang ingin membuat pembelajaran lebih menarik melalui pendekatan gamifikasi. Peserta akan belajar cara menggunakan elemen game seperti poin, tantangan, lencana, dan leaderboard dalam proses belajar-mengajar, serta merancang aktivitas yang menyenangkan dan bermakna untuk berbagai topik pelajaran.<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoNormal\" style=\"text-align:justify\"><b><span style=\"font-size:12.0pt;\r\nline-height:107%;font-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:Calibri;\r\nmso-ansi-language:EN-US\">Baca Panduan ICETy.org di&nbsp;<a href=\"https://drive.google.com/file/d/17i24qtpH5JLYkwIZi8eYTQMaQFzHoBaU/view\" target=\"_blank\">Panduan Platform&nbsp;</a></span></b><span style=\"font-size:\r\n12.0pt;line-height:107%;font-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:\r\nCalibri;mso-ansi-language:EN-US\"><o:p></o:p></span></p>', '<p class=\"MsoListParagraphCxSpFirst\" style=\"margin-left:.7in;mso-add-space:auto;\r\ntext-align:justify;text-indent:-.25in;line-height:115%;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span lang=\"EN-ID\" style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri\">1.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri;mso-ansi-language:EN-US\">Memahami konsep dan\r\nprinsip dasar gamifikasi dalam pendidikan</span><b><span lang=\"EN-ID\" style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri\"><o:p></o:p></span></b></p>\r\n\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left:.7in;mso-add-space:auto;\r\ntext-align:justify;text-indent:-.25in;line-height:115%;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri;mso-ansi-language:EN-US\">2.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n</span></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:115%;\r\nfont-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:Calibri;mso-ansi-language:\r\nEN-US\">Mengenali dan menerapkan elemen gamifikasi seperti poin, tantangan, dan\r\nleaderboard<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left:.7in;mso-add-space:auto;\r\ntext-align:justify;text-indent:-.25in;line-height:115%;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri;mso-ansi-language:EN-US\">3.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n</span></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:115%;\r\nfont-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:Calibri;mso-ansi-language:\r\nEN-US\">Merancang aktivitas pembelajaran berbasis game untuk topik AI/Deep\r\nLearning<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoListParagraphCxSpMiddle\" style=\"margin-left:.7in;mso-add-space:auto;\r\ntext-align:justify;text-indent:-.25in;line-height:115%;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri;mso-ansi-language:EN-US\">4.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n</span></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:115%;\r\nfont-family:&quot;Calibri&quot;,sans-serif;mso-fareast-font-family:Calibri;mso-ansi-language:\r\nEN-US\">Menggunakan platform gamifikasi edukatif seperti Quizizz, Blooket, dan\r\nClasscraft<o:p></o:p></span></p>\r\n\r\n<p class=\"MsoListParagraphCxSpLast\" style=\"margin-left:.7in;mso-add-space:auto;\r\ntext-align:justify;text-indent:-.25in;line-height:115%;mso-list:l0 level1 lfo1\"><!--[if !supportLists]--><span lang=\"EN-ID\" style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri\">5.<span style=\"font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-size-adjust: none; font-kerning: auto; font-optical-sizing: auto; font-feature-settings: normal; font-variation-settings: normal; font-variant-position: normal; font-variant-emoji: normal; font-stretch: normal; font-size: 7pt; line-height: normal; font-family: &quot;Times New Roman&quot;;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span></span><!--[endif]--><span style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri;mso-ansi-language:EN-US\">Mengevaluasi\r\nefektivitas gamifikasi dalam meningkatkan keterlibatan dan hasil belajar siswa</span><span lang=\"EN-ID\" style=\"font-size:12.0pt;line-height:115%;font-family:&quot;Calibri&quot;,sans-serif;\r\nmso-fareast-font-family:Calibri\"><o:p></o:p></span></p>', 23, NULL, NULL, 'ACT_FNLX224', 'MG', '1', '2', 1, 25000, 0, NULL),
('ACT_PCLSb4f', 'ACT_MDLCaea', NULL, '<p class=\"MsoNormal\" style=\"margin-bottom: 0in; line-height: 21px;\"><span style=\"font-weight: bolder;\"><span style=\"font-size: 18pt; line-height: 32px; font-family: Calibri, sans-serif;\">* Sertifikat Pelatihan – Ice Breaking (32 JP)</span></span><span style=\"font-size: 16pt; line-height: 32px; font-family: Calibri, sans-serif;\"><o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin-bottom: 0in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">Sertifikat ini diberikan sebagai bukti bahwa peserta telah mengikuti dan menyelesaikan pelatihan Deep Learning Ice Breaking selama 32 Jam Pelajaran (JP), dengan ketentuan:<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">a. Harus diselesaikan oleh peserta dalam durasi belajar yang telah ditentukan.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">b. Diberikan kepada peserta yang telah menyelesaikan seluruh chapter dan lulus Evaluasi &amp; Ujian Akhir (Post-Test) dengan minimal skor 80%.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">c. Sertifikat ini menandakan bahwa peserta telah mengikuti dan menyelesaikan pelatihan secara lengkap.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.5in; line-height: 21px;\"><span style=\"font-size: 12pt; line-height: 24px; font-family: Calibri, sans-serif;\">&nbsp;</span></p><p class=\"MsoNormal\" style=\"margin-bottom: 0in; line-height: 21px;\"><span style=\"font-weight: bolder;\"><span style=\"font-size: 18pt; line-height: 32px; font-family: Calibri, sans-serif;\">*Sertifikat Kompetensi – Ice Breaking</span></span><span style=\"font-size: 16pt; line-height: 32px; font-family: Calibri, sans-serif;\"><o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin-bottom: 0in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">Sertifikat ini bersifat opsional dan diberikan kepada peserta yang ingin mengukur penguasaan kompetensinya secara lebih mendalam melalui Uji Kompetensi Akhir, dengan ketentuan:<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">a. Sertifikat ini bukan bagian dari pelatihan 32 JP, dan bersifat tambahan<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">b. Dikeluarkan oleh Pelangi Edukasi dan Yayasan TAGAME.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">c. Peserta dapat mengikuti ujian tambahan (Final Exam) dengan biaya terpisah, setelah lulus dengan minimal skor 80%.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">d. Ujian Sertifikat Achievement harus diselesaikan dalam waktu maksimal 1 minggu setelah akun Uji Kompetensi ini diaktifkan.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin-bottom: 0in; line-height: 16.1px;\"></p><p class=\"MsoNormal\" style=\"margin: 0in 0in 0in 0.25in; line-height: 21px;\"><span style=\"font-size: 14pt; line-height: 28px; font-family: Calibri, sans-serif;\">e. Sertifikat diterbitkan jika peserta lulus dengan passing grade minimal 80% pada Uji Kompetensi ini</span></p>', '<p class=\"MsoNormal\"><span style=\"font-weight: bolder; font-size: 24px;\">“Ice Breaker Cerdas: Siap Belajar Deep Learning”</span></p><p class=\"MsoNormal\"><o:p></o:p></p><p></p><p class=\"MsoNormal\"><span style=\"font-size: 18px;\">Kursus dari ice breaker ini, untuk membangun fokus dan kesiapan mental siswa sehingga ice breaker dapat menghubungkan konsep baru dengan pengetahuan lama siswa, selain itu dapat meningkatkan keterlibatan dan partisipasi aktif siswa, juga mendorong kolaborasi dan keterampilan sosial siswa, sehingga dapat meningkatkan motivasi dan rasa ingin tahu siswa dalam mengikuti pembelajaran.</span></p><p><span style=\"font-size: 18px;\"><b>Baca Panduan ICETy.org di <a href=\"https://drive.google.com/file/d/17i24qtpH5JLYkwIZi8eYTQMaQFzHoBaU/view\" target=\"_blank\">Panduan Platform&nbsp;</a></b></span></p>', '<p><span style=\"font-size: 18px;\">1. Menggunakan&nbsp;berbagai ice breaker for deep learning berbasis teknologi (baik pembelajaran onsite maupun online) untuk mempersiapkan pemahaman peserta didik.</span></p><p><span style=\"font-size: 18px;\">2. Merancang dan membuat ice breaker unik sesuai karakter pendidik.</span></p><p><span style=\"font-size: 18px;\">3. Menyusun materi ice breaker for deep learning secara, terstruktur dan menarik disesuaikan dengan level kelas dan materi.</span></p><p><span style=\"font-size: 18px;\">4. Melakukan evaluasi terhadap efektivitas penggunaan ice breaker, serta mengukur hasil belajar peserta melalui post-test.</span></p>', 23, NULL, NULL, 'ACT_FNLXe69', 'MIB', '1', '2', 1, 25000, 0, NULL),
('ACT_PCRS860', 'ACT_DTNGeb8', NULL, '<p>Course Editing Video di Rancang untuk Anda yang ingin menguasai keterampilan editing video secara profesional. Kursus ini terdiri dari 12 pertemuan yang akan membimbing peserta mulai dari dasar interface hingga teknik lanjutan seperti color grading dan efek transisi.</p><p>Silahkan untuk bergabung ke WAG berikut:</p><p><a href=\"https://chat.whatsapp.com/F9HZHDlOLtQFP8sF0IHeu1\" target=\"_blank\"><b>https://chat.whatsapp.com/F9HZHDlOLtQFP8sF0IHeu1</b></a><br></p>', '<p>Course Editing Video untuk membantu peserta memahami alur kerja editing video yang efisien dan kreatif. Premiere Pro merupakan software editing video standar industri yang banyak digunakan oleh kreator konten, filmmaker, maupun profesional di bidang multimedia.</p><p>Melalui kursus ini, peserta akan mempelajari teknik dasar hingga lanjutan seperti timeline editing, audio mixing, penggunaan efek transisi, color correction, hingga rendering video siap tayang.</p>', '<p>Setiap pertemuan akan membantu Anda menguasai topik spesifik seperti:</p><p>Pertemuan 1 – Pengenalan tools dasar</p><p>Pertemuan 2 – Penerapan Video Subtitle</p><p>Pertemuan 3 – Teknik Dasar Videografi</p><p>Pertemuan 4 – Penerapan footage dan Transisi Video</p><p>Pertemuan 5 – Penerapan Effect dari Audio</p><p>Pertemuan 6 – Pengembangan Effect dari Audio</p><p>Pertemuan 7 – Effect Keying</p><p>Pertemuan 8 – Dasar Pewarnaan dan Color Grading</p><p>Pertemuan 9 – Konsep Video Pendek</p><p>Pertemuan 10 – Produksi Video</p><p>Pertemuan 11 – Pengembangan Video</p><p>Pertemuan 12 – Proyek akhir&nbsp;</p>', 28, NULL, NULL, NULL, 'EDC', '2', '2', 0, NULL, 0, NULL),
