(8483, 5018, 'FNL_482', 'Berapakah suhu yang tepat untuk memasak makanan berpotensi bahaya dalam microwave?', '145˚F (63˚C);165˚F (74˚C);155˚F (68˚C);140˚F (60˚C)', 'b', 1),
(8484, 5018, 'FNL_482', 'Mikroorganisme penyebab keracunan makanan tumbuh sangat cepat pada suhu antara?', '0°C - 21°C;3°C - 68°C;5°C - 60°C;21°C - 74°C', 'c', 1),
