(4803, 'ACT_PCLSb4f', 'Penjelasan Modul', NULL, '-', '<p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-weight: bolder;\">🎓 Selamat Datang di Modul Ice Breaker untuk Pembelajaran Deep Learning</span></span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Modul ini dirancang untuk membantu Anda merancang dan menggunakan ice breaker secara strategis, bukan sekadar seru, tetapi juga selaras dengan prinsip pembelajaran mendalam (deep learning).</span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-weight: bolder;\">Melalui 4 chapter dan 12 sesi pembelajaran, Anda akan:</span></span></font></p><ul><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-size: 17.3333px;\"><span style=\"font-size: 12px;\">●</span>&nbsp;</span>Memahami konsep dan manfaat ice breaker</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-size: 17.3333px;\"><span style=\"font-size: 12px;\">●</span>&nbsp;</span>Mencoba berbagai tools digital seperti Zep Quiz, Padlet, dan Jeopardy</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-size: 12px;\">●&nbsp;</span>Mendesain ice breaker yang relevan untuk kelas daring</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-size: 17.3333px;\"><span style=\"font-size: 12px;\">●</span>&nbsp;</span>Menyesuaikan strategi ice breaker dengan tujuan pembelajaran Anda</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-size: 17.3333px;\"><span style=\"font-size: 12px;\">●</span>&nbsp;</span>Mengikuti evaluasi akhir dan mendapatkan sertifikat penyelesaian</span></font></li><li><br></li></ul><p><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: bolder;\">📎</span><b><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px;\">&nbsp;</span><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px;\">Panduan umum tersedia dalam format</span></b><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: bolder;\">&nbsp;</span><a href=\"https://drive.google.com/file/d/15KQ7_agZ8dA5HlMStkZmcSV9tb9KE7vo/view?usp=sharing\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255);\"><b>PDF</b></a></p><p><i style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 18px; font-weight: 700;\"><br></i></p><p style=\"text-align: center;\"><i style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 18px; font-weight: 700;\">💬 “Pembelajaran yang hebat dimulai dari pembuka yang berdampak.”</i></p>', 1, 1, 'https://drive.google.com/file/d/1vGXWgex1nl_U-Xi0oSdpIbr_SGjeP5pg/view?usp=sharing', NULL),
(4804, 'ACT_PCLSb4f', 'Chapter 1 - Ice Breaker Cerdas Untuk Pembelajaran Interaktif', NULL, '-', '<p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Chapter ini memperkenalkan peran penting ice breaker sebagai strategi awal dalam pembelajaran berbasis deep learning. Anda akan mempelajari bagaimana aktivitas sederhana di awal kelas dapat membantu membangun koneksi, memfokuskan perhatian, dan memantik rasa ingin tahu peserta didik.</span></font></p><p><span style=\"font-weight: bolder; font-size: 18px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">🗂️ Aktifitas &amp; Materi yang Anda lakukan:</span></p><ul><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Video – Pengantar dan Macam-Macam Ice Breaker</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Bacaan – Pentingnya Ice Breaker dalam Pembelajaran Deep Learning</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Bacaan – Contoh Ice Breaker Onsite &amp; Online</span></font></li><li><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\">Refleksi Mandiri - Kuesioner – Analisis Penggunaan Ice Breaker</span></font></li></ul><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><br></span></font></p><p style=\"text-align: center; \"><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 18px; font-weight: 700;\"><i>💬 “Awal yang kuat menentukan perjalanan belajar yang berkesan.”</i></span></p>', 2, 1, 'https://drive.google.com/file/d/1DRpRWonIq4Lr_iL2uxgT9VoxyMbw2Ff9/view?usp=drive_link', NULL),
(4805, 'ACT_PCLSb4f', 'Ice Breaker: Aktivitas Kecil, Dampak Besar', NULL, '-', '<p><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 18px; font-weight: bolder;\">Ice Breaker: Aktivitas Kecil, Dampak Besar</span></p><ul><li><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">🎯 Tujuan Pembelajaran:</span></span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">&nbsp;Peserta memahami fungsi strategis ice breaker untuk membangun suasana belajar yang aktif dan menyenangkan, terutama dalam pembelajaran berbasis teknologi dan pendekatan deep learning.</span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">📘 Deskripsi Singkat:</span></span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Ice breaker bukan sekadar aktivitas pemanasan. Sesi ini memperkenalkan peran penting ice breaker dalam membantu siswa lebih fokus, terhubung secara emosional, dan siap untuk menerima materi baru. Disediakan juga beberapa video referensi dari pelaksanaan ice breaker di kelas tatap muka.</span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">🎥 Video Referensi Ice Breaker (Onsite):</span></span></font></p><ul><li><a href=\"http://s.id/VideoIceBreaking1\" target=\"_blank\">Contoh 1 video Ice Breaking</a></li><li><a href=\"http://s.id/VideoIceBreaking2\" target=\"_blank\">Contoh 2 video Ice Breaking</a></li><li><a href=\"http://s.id/VideoIceBreaking3\" target=\"_blank\">Contoh 3 video Ice Breaking</a></li><li><a href=\"http://s.id/VideoIceBreaking4\" target=\"_blank\">Contoh 4 video Ice Breaking</a></li><li><a href=\"https://s.id/VideoIceBreaking5\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); text-indent: -0.25in;\">Contoh 5 video Ice Breaking</a></li><li><a href=\"https://s.id/VideoIceBreaking6\" target=\"_blank\" style=\"background-color: rgb(255, 255, 255); text-indent: -0.25in;\">Contoh 6 video Ice Breaking</a></li><li><br></li></ul></li></ul><p><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: bolder;\">📎 Materi Bacaan &amp; Aktivitas Refleksi tersedia dalam format&nbsp;</span><a href=\"https://drive.google.com/file/d/1KD-uIZztC2ueLnBkzOOuep_YQlYugXrA/view?usp=drive_link\" target=\"_blank\"><span style=\"font-weight: bolder;\">PDF</span></a></p>', 3, 1, 'https://drive.google.com/file/d/1LlUjBk7y64aiiC1hDCiei5lQHnUcRlvR/view?usp=drive_link', NULL),
(4806, 'ACT_PCLSb4f', 'Ice Breaker Dan Deep Learning: Lebih Dari Sekadar Pemanasan', NULL, '-', '<p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><b>Ice Breaker Dan Deep Learning: Lebih Dari Sekadar Pemanasan</b></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">🎯 Tujuan Pembelajaran:</span></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">&nbsp;</span>Membangun suasana belajar yang kondusif dan mengenalkan konsep deep learning melalui penggunaan ice breaker yang strategis dan relevan.</span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">📘 Deskripsi Singkat:</span></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Ice breaker bukan hanya aktivitas pemanasan, tetapi bagian penting dari strategi pembelajaran. Sesi ini membahas bagaimana ice breaker dapat meningkatkan fokus, partisipasi, dan keterlibatan peserta secara aktif sebelum masuk ke materi inti. Peserta akan mempelajari konsep dasar, alasan pentingnya ice breaker dalam pembelajaran teknologi, serta cara mengaitkannya secara efektif dengan materi deep learning.</span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">📎 Materi Bacaan &amp; Aktivitas Refleksi tersedia dalam format&nbsp;<a href=\"https://drive.google.com/file/d/1aC7sIt7RTT8EkKRp9r6lSozmU32iyJhv/view?usp=drive_link\" target=\"_blank\">PDF</a></span></span></font></p>', 4, 1, 'https://drive.google.com/file/d/1D-ZsUAoeMHzc1hK3bMaiFSEWKEBg2wmr/view?usp=sharing', NULL),
(4807, 'ACT_PCLSb4f', '11 Ice Breaker Seru Untuk Kelas Onsite & Online', NULL, '-', '<p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-weight: bolder;\">11 Ice Breaker Seru untuk Kelas Onsite &amp; Online</span></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 11pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\"><span style=\"font-family: Cambria, serif; font-size: 17.3333px; white-space-collapse: collapse;\">🎯 Tujuan Pembelajaran:</span><br></span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Peserta mengenal berbagai jenis ice breaker onsite dan online yang dirancang untuk meningkatkan fokus, interaksi, serta keterlibatan siswa dalam pembelajaran berbasis deep learning.</span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: 700;\">📘 Deskripsi Singkat:</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Sesi ini memperkenalkan lebih dari 10 contoh aktivitas ice breaker yang bisa langsung diterapkan dalam kelas tatap muka maupun daring. Setiap aktivitas dirancang untuk mengaktifkan pemikiran kritis, mendorong refleksi, hingga membangun rasa ingin tahu siswa.&nbsp;</span></font><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">Ice breaker yang tepat bukan hanya membuat pembelajaran lebih hidup, tetapi juga membuka jalan menuju pemahaman yang lebih dalam dan bermakna.</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">✨</span><b>&nbsp;Jangan lewatkan sesi ini, karena di sinilah peserta akan menemukan inspirasi praktis yang bisa langsung digunakan di kelas mereka!</b></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><span style=\"font-weight: bolder;\">📎 Detail contoh dan panduan implementasi tersedia dalam file&nbsp;<a href=\"https://drive.google.com/file/d/18bQ9cHA27p29WvRXtmyKdKQgaZvHUADv/view?usp=drive_link\" target=\"_blank\">PDF</a>.</span></span></font></p>', 5, 1, 'https://drive.google.com/file/d/1pvNqN2kvsZemutRwk2-G8YjH1xkhW-BX/view?usp=sharing', NULL),
(4808, 'ACT_PCLSb4f', 'Refleksi Ice Breaker: Sudahkah Saya Membangun Kelas Yang Siap Belajar', NULL, 'https://youtu.be/dpuEVMfP-i0', '<p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><span style=\"font-weight: bolder;\">Refleksi Ice Breaker: Sudahkah Saya Membangun Kelas yang Siap Belajar?</span></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 11pt; font-family: Arial, sans-serif; color: rgb(0, 0, 0); background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; white-space-collapse: preserve;\"><span style=\"font-family: Cambria, serif; font-size: 17.3333px; white-space-collapse: collapse;\">🎯 Tujuan Pembelajaran:</span><br></span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Peserta melakukan refleksi mandiri untuk menganalisis sejauh mana ice breaker telah digunakan secara efektif dalam praktik mengajar, serta menemukan area yang bisa ditingkatkan.</span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: 700;\">📘 Deskripsi Singkat:</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Pada sesi ini, Anda akan mengisi sebuah kuesioner reflektif terkait pengalaman dan kebiasaan Anda dalam menggunakan ice breaker di kelas.&nbsp;</span></font><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">Pertanyaan dirancang untuk membantu Anda:</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px;\">1. Mengevaluasi cara Anda memulai pembelajaran</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">2. Menyadari potensi perbaikan strategi ice breaking</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">3. Menemukan gaya ice breaker yang paling sesuai dengan konteks kelas Anda</span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\"><br></span></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><b>💡 Jawaban Anda akan menjadi dasar yang berharga untuk sesi-sesi berikutnya dalam modul ini.&nbsp;</b></span></font></p><p dir=\"ltr\" style=\"margin-top: 12pt; margin-bottom: 12pt; line-height: 1.38;\"><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">Luangkan waktu sejenak untuk menjawab dengan jujur dan reflektif.</span></p>', 6, 1, 'https://drive.google.com/file/d/1UI5q5RKacYA_zBadVwIvBX03ap3bjdIJ/view?usp=drive_link', NULL),
