(4810, 'ACT_PCLSb4f', 'Chapter 2 - Ice Breaker Kolaboratif di Kelas Online', NULL, '-', '<p class=\"MsoNormal\" style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><b>Chapter</b> ini mengajak Anda mengeksplorasi tools digital populer untuk membuat ice breaker kolaboratif dalam pembelajaran daring. Anda akan diajak mencoba, mendesain, dan menyusun ice breaker berbasis platform digital yang interaktif dan kontekstual.</span></font></p><p class=\"MsoNormal\" style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><span style=\"font-size: 16px;\">🗂️<b> </b></span><span style=\"text-align: left; font-size: 17.3333px;\"><font color=\"#000000\" face=\"Cambria, serif\"><b>Aktifitas &amp; Materi yang Anda lakukan:&nbsp;</b></font></span></p><ul><li style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><span style=\"font-size: 16px;\">●&nbsp; </span><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Bacaan – Mengapa Ice Breaker Kolaboratif Sangat Dibutuhkan</span></font></li><li style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><span style=\"font-size: 16px;\">●&nbsp; </span><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Bacaan – 10 Ice Breaker Kolaboratif untuk Kelas Daring</span></font></li><li style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><span style=\"font-size: 16px;\">●&nbsp;&nbsp;</span><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Bacaan - Panduan Tools – Zep Quiz, Padlet, Jeopardy</span></font></li><li style=\"text-align: left; margin: 12pt 0in; break-after: avoid;\"><span style=\"font-size: 16px;\">●&nbsp;&nbsp;</span><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Webinar/Video – Praktik Langsung Tools Ice Breaker</span></font></li><li><br></li><li style=\"text-align: center; margin: 12pt 0in; break-after: avoid;\"><font color=\"#72849a\"><span style=\"font-size: 16px;\"><b>💬 </b></span></font><font face=\"Cambria, serif\"><b style=\"\"><i style=\"\"><font color=\"#000000\"><span style=\"font-size: 18px;\">\" Teknologi bukan sekadar alat, tapi jembatan untuk membangun keterhubungan di awal kelas \".</span></font></i></b></font></li></ul><p class=\"MsoNormal\" style=\"margin: 12pt 0in; text-align: justify; break-after: avoid;\"></p>', 8, 1, 'https://drive.google.com/file/d/1T31U-LD4f0OjOhzCFhvUIaTXotyJisHA/view?usp=drive_link', NULL),
(4811, 'ACT_PCLSb4f', 'Mengapa Ice Breaker Kolaboratif Penting Dalam Kelas Online?', NULL, '-', '<p><b>&nbsp;</b><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><b>Mengapa Ice Breaker Kolaboratif Penting Dalam Kelas Online?</b></span></font></p><p><b>🎯&nbsp;</b><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: 700;\">Tujuan Pembelajaran:</span></p><p><b>&nbsp;</b><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Peserta memahami tantangan utama pembelajaran daring dan mengenali peran strategis ice breaker kolaboratif dalam menciptakan keterlibatan, interaksi sosial, dan pembelajaran yang mendalam.&nbsp;</span></font></p><div><br></div><p>📘&nbsp;<span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 17.3333px; font-weight: 700;\">Deskripsi Singkat :</span></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Pembelajaran daring bukan hanya memindahkan kelas ke layar — tapi juga menghadirkan tantangan baru: siswa mudah terdistraksi, enggan berinteraksi, dan kehilangan fokus.&nbsp;</span></font><span style=\"font-size: 17.3333px; color: rgb(0, 0, 0); font-family: Cambria, serif;\">Sesi ini akan membuka wawasan Anda mengenai mengapa ice breaker kolaboratif bukan lagi pelengkap, tapi justru bagian penting dari strategi pembelajaran online.</span></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\">Anda akan memahami 7 tujuan utama penggunaan ice breaker dalam konteks daring, mulai dari membangun fokus mental hingga mendorong refleksi metakognitif.</span></font></p><p><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><br></span></font></p><p>&nbsp; &nbsp; &nbsp;📎<b>&nbsp;</b><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 17.3333px;\"><b>Materi Bacaan &amp; Aktivitas Refleksi tersedia dalam format</b></span></font>&nbsp;<a href=\"https://drive.google.com/file/d/1dMCoD6eEPAwKN3ULofRXdADRf-PpJUzP/view?usp=drive_link\" target=\"_blank\" style=\"color: rgb(15, 105, 242); background-color: rgb(255, 255, 255); font-size: 16px; text-align: justify;\"><b>PDF</b></a></p><p><br></p><p style=\"text-align: center; \"><b>&nbsp; &nbsp; &nbsp;</b>💬<b>&nbsp;</b><i><span style=\"color: rgb(0, 0, 0); font-family: Cambria, serif; font-size: 18px; font-weight: 700;\">&nbsp;</span></i><font color=\"#000000\" face=\"Cambria, serif\"><span style=\"font-size: 18px;\"><b><i>“Sudahkah saya menciptakan kelas online yang benar-benar hidup dan terhubung?”</i></b></span></font></p>', 9, 1, 'https://drive.google.com/file/d/1dI7njVWZm7W__7CSqC-uOsoUbOlyUHFC/view?usp=sharing', NULL);
