(1302, 'USR_FKR3f4', 'ACT_MCRSe01', '1/CRS/OC/ICETy/VIII/2026', '1', 'https://is3.cloudhost.id/tbh-v2/certificate/1784361482_FIKRI 2_CERTIFICATE_CERTIFICATE OF COMPLETION IN MICROSOFT OFFICE.pdf', '2026-07-18 14:58:01', 1, '<p>Sertifikat ini membuktikan kompetensi anda dalam mengelola dokumen, data, presentasi, dan komunikasi digital secara efektif untuk kebutuhan profesional maupun akademik.</p>', '<p>6,</p><p>Microsoft Word: Basic Editing &amp; Formatting</p><p>Microsoft Word: Styles, Layout, &amp; Tables</p><p>Microsoft Excel: Basic Formulas</p><p>Microsoft Excel: Functions &amp; Data Formatting</p><p>Microsoft Excel: Charts &amp; Data Visualization</p><p>Microsoft Power Point : Basic Editing Styles &amp; Layout</p>', '0', NULL, '18 July 2026', NULL);
