INSERT INTO `tb_why_choose_us` (`ID_WHY`, `TITLE_WHY`, `IMAGE_WHY`, `TEXT_WHY`) VALUES
(1, 'Expert Educators and Instructors', 'https://expo-dev.is3.cloudhost.id/IMAGE_WHY/Image-Why-1763723057-1763723057.jpeg', 'Our teachers and ICETy instructors work hand-in-hand to guide students in both academic and creative excellence. With international teaching standards and hands-on mentoring, every child receives the support they need to explore their full potential.'),
(2, 'Project-Based Learning with Real Impact', 'https://expo-dev.is3.cloudhost.id/IMAGE_WHY/Image-Why-1763723074-1763723074.jpeg', 'Through our collaboration with ICETy, students learn by creating. From videography to digital storytelling, every project is designed to strengthen critical thinking, creativity, and teamwork — preparing them for the global stage.'),
(3, 'Safe, Supportive, and Inspiring Environment', 'https://expo-dev.is3.cloudhost.id/IMAGE_WHY/Image-Why-1763723084-1763723084.jpeg', 'WPJ Global School provides a nurturing environment where students can grow freely and express themselves confidently. Combined with ICETy’s secure digital platform, parents can trust that their children learn and create safely, both offline and online.');
